{"content": "#!/usr/bin/env node
// migrate-data.js — Reads all JSONs and inserts into Postgres via Docker exec
// Usage: node scripts/migration/migrate-data.js

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const REPO = path.resolve(__dirname, '../..');
const CONTAINER = process.env.PG_CONTAINER || 'postgres';

function pgEscape(val) {
  if (val === null || val === undefined) return 'NULL';
  const str = JSON.stringify(val);
  // Escape single quotes by doubling them, then wrap in single quotes
  return "'" + str.replace(/'/g, "''") + "'";
}

async function main() {
  const slug = 'nexa-paraguay';
  const locale = 'nl';

  console.log(`📦 Migrating tenant: ${slug}`);

  // 1. Load content JSON
  const content = JSON.parse(fs.readFileSync(path.join(REPO, 'content', `${locale}.json`), 'utf-8'));
  console.log(`   content loaded`);

  // 2. Load page configs
  const pagesDir = path.join(REPO, 'nexa-pages');
  const pageConfig = {};
  for (const file of fs.readdirSync(pagesDir).filter(f => f.endsWith('.json'))) {
    const s = file.replace('.json', '');
    pageConfig[s] = JSON.parse(fs.readFileSync(path.join(pagesDir, file), 'utf-8'));
  }
  console.log(`   pages: ${Object.keys(pageConfig).length}`);

  // 3. Load images
  const images = JSON.parse(fs.readFileSync(path.join(REPO, 'images.json'), 'utf-8'));
  console.log(`   images: ${images.totalImages || 'N/A'}`);

  // 4. Load site config
  const siteConfig = JSON.parse(fs.readFileSync(path.join(REPO, 'site.json'), 'utf-8'));
  console.log(`   site: ${siteConfig.vertical}`);

  // 5. Build the SQL
  const sql = `
    INSERT INTO tenant_config (tenant_slug, domain, content, page_config, images, site_config, meta)
    VALUES (
      '${slug}',
      '${siteConfig.domain || 'nexa.paragu-ai.com'}',
      ${pgEscape(content)}::jsonb,
      ${pgEscape(pageConfig)}::jsonb,
      ${pgEscape(images)}::jsonb,
      ${pgEscape(siteConfig)}::jsonb,
      ${pgEscape({ migratedAt: new Date().toISOString() })}::jsonb
    )
    ON CONFLICT (tenant_slug) 
    DO UPDATE SET 
      content = EXCLUDED.content,
      page_config = EXCLUDED.page_config,
      images = EXCLUDED.images,
