  const { locale, slug } = await params
  const data = await loadPageData(locale, slug)
  if (!data) return {}
  return { 
    title: data.pageConfig?.title || data.content?.siteName || 'Nexa Paraguay', 
    alternates: { languages: { es: `/es/${slug}`, en: `/en/${slug}`, nl: `/nl/${slug}`, de: `/de/${slug}` } } 
  }
}

